import {
  successResponse,
  fromNeverthrowError,
  outputAndExit,
} from '@/cli/output';

import { registerOrigin } from '@/operations/register';
import { getWalletOrExit } from '../lib/get-wallet-or-exit';

import type { RegisterInput } from '@/operations/register';
import type { Command } from '@/types';

const SURFACE = 'cli:register';

export const registerCommand: Command<RegisterInput> = async args => {
  const wallets = await getWalletOrExit(args);

  const result = await registerOrigin(
    { url: args.url },
    { surface: SURFACE, wallets, flags: args }
  );

  if (result.isErr()) {
    return outputAndExit(fromNeverthrowError(result), args);
  }

  return outputAndExit(successResponse(result.value), args);
};
