import z from 'zod';
import { ok, err } from '@agentcash/neverthrow';

import { executeFetch } from './fetch';
import { ensureProtocol } from '@/shared/url';
import { RequestMethod } from '@/shared/request/types';
import { safeParseJson } from '@/shared/neverthrow/json';

import type { Wallets } from '@/wallet';
import type { GlobalFlags } from '@/types';

const X402SCAN_URL =
  'https://www.x402scan.com/api/x402/registry/register-origin';
const MPPSCAN_URL = 'https://www.mppscan.com/api/mpp/register';

export interface RegisterInput {
  url: string;
}

export interface RegisterOptions {
  surface: string;
  wallets: Wallets;
  flags: GlobalFlags;
}

const x402scanResponseSchema = z.object({
  success: z.boolean(),
  registered: z.number().optional(),
  failed: z.number().optional(),
  total: z.number().optional(),
  source: z.string().optional(),
});

const mppscanDoneSchema = z.object({
  type: z.literal('done'),
  origin: z.object({
    id: z.string(),
    origin: z.string(),
    name: z.string(),
  }),
  resourceCount: z.number(),
});

async function registerX402Scan(url: string, options: RegisterOptions) {
  const { surface, wallets, flags } = options;

  const fetchResult = await executeFetch(
    {
      url: X402SCAN_URL,
      method: RequestMethod.POST,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ origin: url }),
    },
    { surface, wallets, flags, params: {} }
  );

  if (fetchResult.isErr()) return fetchResult;

  const { response } = fetchResult.value;
  if (!response.ok) {
    return err('register', surface, {
      cause: 'x402scan_http' as const,
      message: `x402scan returned ${response.status} ${response.statusText}`,
    });
  }

  const text = await response.text();
  const jsonResult = safeParseJson(surface, text);
  if (jsonResult.isErr()) return jsonResult;

  const parsed = x402scanResponseSchema.safeParse(jsonResult.value);
  if (!parsed.success) {
    return err('register', surface, {
      cause: 'x402scan_parse' as const,
      message: 'Invalid x402scan response',
    });
  }

  return ok(parsed.data);
}

async function registerMppscan(url: string, options: RegisterOptions) {
  const { surface, wallets, flags } = options;

  const fetchResult = await executeFetch(
    {
      url: MPPSCAN_URL,
      method: RequestMethod.POST,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ url }),
    },
    { surface, wallets, flags, params: {} }
  );

  if (fetchResult.isErr()) return fetchResult;

  const { response } = fetchResult.value;
  if (!response.ok) {
    return err('register', surface, {
      cause: 'mppscan_http' as const,
      message: `mppscan returned ${response.status} ${response.statusText}`,
    });
  }

  const text = await response.text();
  const lines = text.trim().split('\n');
  for (let i = lines.length - 1; i >= 0; i--) {
    const lineResult = safeParseJson(surface, lines[i]!);
    if (lineResult.isErr()) continue;
    const parsed = mppscanDoneSchema.safeParse(lineResult.value);
    if (parsed.success) return ok(parsed.data);
  }

  return err('register', surface, {
    cause: 'mppscan_parse' as const,
    message: 'No done message in mppscan response',
  });
}

export async function registerOrigin(
  input: RegisterInput,
  options: RegisterOptions
) {
  const url = ensureProtocol(input.url);

  const [x402Result, mppResult] = await Promise.all([
    registerX402Scan(url, options),
    registerMppscan(url, options),
  ]);

  if (x402Result.isErr() && mppResult.isErr()) {
    return err('register', options.surface, {
      cause: 'register_failed' as const,
      message: `Both registries failed. x402scan: ${x402Result.error.message}. mppscan: ${mppResult.error.message}`,
    });
  }

  return ok({
    x402scan: x402Result.isOk()
      ? x402Result.value
      : { success: false as const, error: x402Result.error.message },
    mppscan: mppResult.isOk()
      ? mppResult.value
      : { success: false as const, error: mppResult.error.message },
  });
}
